SELECT total_tests
FROM health_tests
WHERE state_id = 0;

SELECT worker_name, role
FROM health_workers
WHERE state_id = 1 AND role = 'nurse';

SELECT equipment_name, condition, SUM(quantity) AS total_quantity
FROM health_equipment
GROUP BY equipment_name, condition;

SELECT service_type, COUNT(service_type) AS service_count
FROM health_services
GROUP BY service_type;

SELECT total_tests, testing_ratio, MAX(report_date) AS latest_report_date
FROM health_tests
WHERE state_id = 0;

SELECT state_id, SUM(total_tests) AS total_tests_conducted
FROM health_tests
GROUP BY state_id;
